class Solution:
    def validDigit(self, n, x):
        digits = []
        temp = n
        if temp == 0:
            digits = [0]
        else:
            while temp > 0:
                digits.append(temp % 10)
                temp //= 10
            digits.reverse()
        contains = x in digits
        starts = digits[0] == x
        return contains and not starts

